import{_ as d,C as l,o as c,c as p,a1 as n,E as t,w as i,a as o,j as a}from"./chunks/framework.BX4nIuL2.js";const _=JSON.parse('{"title":"3D printing background","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/3_3dprinter/1.3Dprintingbackground.md","filePath":"courses/fab-course/doc/3_3dprinter/1.3Dprintingbackground.md"}'),u={name:"courses/fab-course/doc/3_3dprinter/1.3Dprintingbackground.md"};function m(g,e,h,b,f,w){const s=l("font"),r=l("center");return c(),p("div",null,[e[5]||(e[5]=n('<h1 id="_3d-printing-background" tabindex="-1">3D printing background <a class="header-anchor" href="#_3d-printing-background" aria-label="Permalink to &quot;3D printing background&quot;">​</a></h1><h2 id="_1-basic-knowledge" tabindex="-1">1.Basic knowledge <a class="header-anchor" href="#_1-basic-knowledge" aria-label="Permalink to &quot;1.Basic knowledge&quot;">​</a></h2><p>3D printing technology (also called Rapid Prototyping) is an additive computer controlled processes that builds part inside a machine, layer by layer, using a variety of materials and processes. It&#39;s cool that 3D printing can output physical prototypes directly from the computer. The invention time is similar with CNC , in the late 1980s .Although it is not so popular with CNC ,it transformed our thinking about prototype making. This ability has great push forward product development. In addition, 3D printing has special advantage in complex model, inner flow channel, cavity, thin wall, and rib which are difficult to make by any other method. The first technology of 3D printing called SLA(Stereolithography Apparatus)found by <a href="https://www.3dsystems.com/about-us#timeline" target="_blank" rel="noreferrer">Chuck Hull</a></p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/1983_0.jpeg" width="100%" alt="图片名称" align="middle">',4)),t(r,null,{default:i(()=>[t(s,{size:"1"},{default:i(()=>[...e[0]||(e[0]=[o("Chuck Hull creates the first-ever 3D printed part, inventing Stereolithography",-1)])]),_:1})]),_:1}),e[6]||(e[6]=n('<p>Normally,we would use stl formate to save data ,which covered with triangle surface.</p><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/WX20230226-170029.png" alt=""></p><h2 id="_2-work-flow" tabindex="-1">2.Work flow <a class="header-anchor" href="#_2-work-flow" aria-label="Permalink to &quot;2.Work flow&quot;">​</a></h2><p>The basic principle is the following:</p><p><img src="https://gitlab.com/picbed/bed/uploads/726cd0c70866e257241b6f8ed0dada49/How-3D-Printing-Works--1030x309.png" alt=""></p><p>Reference from <a href="http://my3dconcepts.com/explore/how-3d-printing-works/" target="_blank" rel="noreferrer">my 3dconcepts</a> Watch the video from <a href="https://www.youtube.com/watch?v=Llgko_GpXbI" target="_blank" rel="noreferrer">YouTuBe</a> to get more detail.</p><h2 id="_3-different-kinds-of-3d-printing" tabindex="-1">3. Different kinds of 3D printing <a class="header-anchor" href="#_3-different-kinds-of-3d-printing" aria-label="Permalink to &quot;3. Different kinds of 3D printing&quot;">​</a></h2><p>According to <a href="https://www.iso.org/obp/ui/#iso:std:iso-astm:52900:ed-1:v1:en:term:2.1.2" target="_blank" rel="noreferrer">ISO/ASTM 52900:2015(en)Additive manufacturing — General principles — Terminology</a>, we can find the following Process categories</p><p><img src="https://gitlab.com/picbed/bed/uploads/f2fde33c0971363a778ec835432f4f62/Additive_Manufacturing_Technologies_Poster.jpg" alt=""> Reference from <a href="https://www.3dhubs.com/guides/3d-printing/" target="_blank" rel="noreferrer">3D hubs</a></p><p>The following can give you some basic guide to choice which kinds of 3D printing meet your requirment <img src="https://gitlab.com/picbed/bed/uploads/7bff2cde2521b6c4b048eed3b1381045/2-functional.png" alt=""></p><p>Reference from <a href="https://www.3dhubs.com/guides/3d-printing/" target="_blank" rel="noreferrer">3D hubs</a></p><h4 id="_3-1-material-extrusion-fdm" tabindex="-1">3.1 Material extrusion(FDM) <a class="header-anchor" href="#_3-1-material-extrusion-fdm" aria-label="Permalink to &quot;3.1 Material extrusion(FDM)&quot;">​</a></h4><p>Material is selectively dispensed through a nozzle or orifice</p><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/fdmdetail.png" alt=""><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/fdm.png" alt=""></p><h4 id="_3-2-vat-photopolymerization-sla-dlp-lcd" tabindex="-1">3.2 Vat photopolymerization(SLA,DLP，LCD) <a class="header-anchor" href="#_3-2-vat-photopolymerization-sla-dlp-lcd" aria-label="Permalink to &quot;3.2 Vat photopolymerization(SLA,DLP，LCD)&quot;">​</a></h4><p>Liquid photopolymer in a vat is selectively cured by light-activated polymerization</p><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/sladlplcd.png" alt=""> DLP 3D printing used in high precision model especial especial lost wax casting model for example jewelry. <img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/Lost-Wax-Casting-Printing-How-It-Works.png" alt=""><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/dlp1.png" alt=""><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/dlpquality.png" alt=""> LCD 3D printing is a cheap method which use screen to solid resign.</p><h4 id="_3-3-powder-bed-fusion-sls-slm" tabindex="-1">3.3 Powder bed fusion(SLS,SLM) <a class="header-anchor" href="#_3-3-powder-bed-fusion-sls-slm" aria-label="Permalink to &quot;3.3 Powder bed fusion(SLS,SLM)&quot;">​</a></h4><p>Thermal energy selectively fuses regions of a powder bed <img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/slsunnc.png" alt=""></p><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/SLMMDOE.png" alt=""></p><h4 id="_3-4-material-jetting-mj" tabindex="-1">3.4 Material jetting(MJ) <a class="header-anchor" href="#_3-4-material-jetting-mj" aria-label="Permalink to &quot;3.4 Material jetting(MJ)&quot;">​</a></h4><p>Droplets of build material are selectively deposited</p><img src="https://gitlab.com/picbed/bed/uploads/8cb54ad1fc010f87dbd88b8009338e92/mjf.gif" width="1920" alt="图片名称" align="middle"><h4 id="_3-5-polyjet" tabindex="-1">3.5 Polyjet <a class="header-anchor" href="#_3-5-polyjet" aria-label="Permalink to &quot;3.5 Polyjet&quot;">​</a></h4><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/stratasys-j750-front-panorama.jpeg" alt=""><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/WX20230226-232437@2x.png" alt=""><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/polyjetrgb.png" alt=""></p><h2 id="_4-3d-printing-vs-traditional-manufacture" tabindex="-1">4. 3D printing VS Traditional Manufacture <a class="header-anchor" href="#_4-3d-printing-vs-traditional-manufacture" aria-label="Permalink to &quot;4. 3D printing VS Traditional Manufacture&quot;">​</a></h2><p>When we process one part ,normally we can choice additive technology(3D printing) ,subtractive technology(For example CNC, milling, lathe, Wire cutting) or formative manufacturing technology(Injection molding). They have their own advantage and disadvantage.</p><ul><li><p>Cost:</p><ul><li>Additive technology has advantage in prototype test or Customized part;</li><li>Subtractive technology is typically more economical when make parts in the 100 pcs;</li><li>Formative manufacturing has advantage in mass production. <img src="https://gitlab.com/picbed/bed/uploads/34ce15c03fb33e4da820b20ad2b9584e/WX20190619-132652_2x.png" alt=""></li></ul></li><li><p>Geometry</p><ul><li>Additive technology can have complex geometry(inner flow channel, cavity, thin wall, and rib );</li><li>Subtractive technology has require in geometry. For example CNC can&#39;t process inner flow channel which bend by itself;</li><li>Formative manufacturing has more require in geometry. For example injection need draft angle in molding. In addition injection molding can&#39;t make complex inner flow channel.</li></ul></li><li><p>Material:</p><ul><li>Additive technology has require in material ,every machine would Specified material. For example FDM 3D printing normally use ABS and PLA. So it would influence the effect of part;</li><li>Subtractive technology can process almost every solid, for example metal, plastic ,wood, etc;</li><li>Formative manufacture could process material mainly in plastic.</li></ul></li><li><p>Quality: Normally ,subtractive technology is similar with formative technology, and they are better then additive technology</p></li><li><p>Size:</p><ul><li>Additive technology has requirement in part size ,the small the better;</li><li>Subtractive technology and formative technology &#39;s size could much bigger than additive technology</li></ul></li></ul><h2 id="_5-design-rule" tabindex="-1">5. Design rule <a class="header-anchor" href="#_5-design-rule" aria-label="Permalink to &quot;5. Design rule&quot;">​</a></h2><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/designrule.png" alt=""></p><h2 id="_6-tendency" tabindex="-1">6. Tendency <a class="header-anchor" href="#_6-tendency" aria-label="Permalink to &quot;6. Tendency&quot;">​</a></h2>',31)),t(r,null,{default:i(()=>[...e[1]||(e[1]=[o("Fast delivery",-1)])]),_:1}),e[7]||(e[7]=a("p",null,[a("img",{src:"https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/FASTDEVEILY.png",alt:""})],-1)),t(r,null,{default:i(()=>[...e[2]||(e[2]=[o("Diversity customization",-1)])]),_:1}),e[8]||(e[8]=a("p",null,[a("img",{src:"https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/TEXURE.png",alt:""})],-1)),t(r,null,{default:i(()=>[...e[3]||(e[3]=[o("Lightweight",-1)])]),_:1}),e[9]||(e[9]=a("p",null,[a("img",{src:"https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/GENERATIVEDESIGN.JPG",alt:""})],-1)),t(r,null,{default:i(()=>[...e[4]||(e[4]=[o("design first",-1)])]),_:1}),e[10]||(e[10]=n('<img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/fdmgif.gif" width="1920" alt="图片名称" align="middle"><h2 id="_7-reference" tabindex="-1">7.Reference <a class="header-anchor" href="#_7-reference" aria-label="Permalink to &quot;7.Reference&quot;">​</a></h2><ul><li><a href="./www.makerbot.com.html">Makerbot</a> build <a href="http://thingiverse.com/" target="_blank" rel="noreferrer">Thingiverse</a> which is the biggest open source 3D printing model community in the world. Maker can download the model they need. It lows down the hardness in design.</li><li><a href="http://ultimaker.com" target="_blank" rel="noreferrer">Ultimaker</a> provide <a href="https://ultimaker.com/en/products/ultimaker-cura-software" target="_blank" rel="noreferrer">Cura</a> which is easy to set 3D printing parameter</li><li><a href="https://bambulab.com/en" target="_blank" rel="noreferrer">Bambambulab </a>build <a href="https://makerworld.com/" target="_blank" rel="noreferrer">MakerWorld</a></li><li><a href="https://cults3d.com/" target="_blank" rel="noreferrer">Cults3d</a></li></ul>',3))])}const v=d(u,[["render",m]]);export{_ as __pageData,v as default};
